external_knowledge:
- "pups_survive" refers to the number of pups that survived in a litter;
- "pups_survive_rate" is the survival rate of the pups, calculated as the number of pups that survived divided by the total number of pups born;
- A survival rate of 1.0 indicates that all pups in the litter survived.

sql:
SELECT pups_survive
FROM litters
WHERE pups_survive_rate = 1.0;

SELECT AVG(pups_survive_rate) AS average_survival_rate
FROM litters
WHERE experiment_id = 1;

SELECT MAX(pups_born_alive) AS max_pups_born_alive
FROM litters
WHERE experiment_id = 0;

